phase1.code:
#include <iostream>
#include <string>

int main() {
    std::cout << "=== Player Inventory ===" << std::endl;

    // Array of strings (inventory)
    std::string inventory[5] = {"Sword", "Shield", "Potion", "Key", "Gold Coin"};

    // Accessing elements
    std::cout << "First item: " << inventory[0] << std::endl;
    std::cout << "Third item: " << inventory[2] << std::endl;

    // Looping through array
    std::cout << "\nInventory:" << std::endl;
    for (int i = 0; i < 5; i++) {
        std::cout << "  " << (i + 1) << ". " << inventory[i] << std::endl;
    }

    // Array of ints (player stats)
    int playerStats[4] = {100, 15, 10, 25};  // health, attack, defense, speed

    std::cout << "\n=== Player Stats ===" << std::endl;
    std::cout << "Health: " << playerStats[0] << std::endl;
    std::cout << "Attack: " << playerStats[1] << std::endl;
    std::cout << "Defense: " << playerStats[2] << std::endl;
    std::cout << "Speed: " << playerStats[3] << std::endl;

    // Modifying array elements
    playerStats[0] = 120;  // Health increased!
    std::cout << "\nHealth increased to: " << playerStats[0] << std::endl;

    // Array of enemy health
    int enemyHealth[3] = {30, 45, 20};

    std::cout << "\n=== Enemy Health ===" << std::endl;
    for (int i = 0; i < 3; i++) {
        std::cout << "Enemy " << (i + 1) << ": " << enemyHealth[i] << " HP" << std::endl;
    }

    // Multi-dimensional array (grid)
    int grid[3][3] = {
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9}
    };

    std::cout << "\n=== Grid ===" << std::endl;
    for (int row = 0; row < 3; row++) {
        for (int col = 0; col < 3; col++) {
            std::cout << grid[row][col] << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}

