#include <iostream>
#include <string>

int main() {
    std::string enemyNames[5] = {"Goblin", "Orc", "Skeleton", "Dragon", "Golem"};
    int enemyHealth[5] = {30, 50, 25, 200, 70};

    std::cout << "=== Enemy List ===" << std::endl;
    for (int i = 0; i < 5; i++) {
        std::cout << enemyNames[i] << ": " << enemyHealth[i] << " HP" << std::endl;
    }

    // Damage Skeleton
    std::cout << "\nSkeleton takes 10 damage!" << std::endl;
    enemyHealth[2] -= 10;

    std::cout << "\n=== Updated Enemy List ===" << std::endl;
    for (int i = 0; i < 5; i++) {
        std::cout << enemyNames[i] << ": " << enemyHealth[i] << " HP" << std::endl;
    }

    return 0;
}
